<template><view class="page"><xy-header title="预约详情"/><view v-if="item" class="wrap"><view class="card"><text class="status">{{labels[item.status]||item.status}}</text><text>预约号：{{item.reservationNo}}</text><text>{{item.reservationDate}} {{item.startTime}}-{{item.endTime}}</text><text>{{item.storeName}} · {{item.zoneName}}{{item.seatCode}}</text><text>核销码：{{item.verifyCode}}</text><text>{{item.address}} {{item.phone}}</text></view><button v-if="item.status==='BOOKED'" class="cancel" @click="cancel">取消预约</button></view></view></template>
<script>import{appRequest,ensureMemberSession,showRequestError}from'../../utils/api';export default{data(){return{reservationNo:'',item:null,labels:{BOOKED:'待到场',CHECKED_IN:'已签到',CANCELED:'已取消',NO_SHOW:'爽约'}}},onLoad(q){this.reservationNo=q.reservationNo;this.load()},methods:{async load(){try{await ensureMemberSession();this.item=await appRequest({url:`/app/reservations/${this.reservationNo}`})}catch(e){showRequestError(e)}},async cancel(){try{await appRequest({url:`/app/reservations/${this.reservationNo}/cancel`,method:'POST'});this.load()}catch(e){showRequestError(e)}}}}</script><style scoped>.page{min-height:100vh;background:var(--xy-bg)}.wrap{padding:28rpx}.card{display:flex;flex-direction:column;gap:20rpx;padding:32rpx;border-radius:24rpx;background:#fff}.status{font-size:36rpx;font-weight:700;color:var(--xy-primary)}.cancel{margin-top:24rpx;color:var(--xy-danger)}</style>
